// @venom: browser
import React from "../jsx-runtime"; import type { ScoredIncident } from "../data/types";
interface RiskPanelProps { incidents:ScoredIncident[]; }
export default function RiskPanel({incidents}:RiskPanelProps){ const counts={Critical:0,Elevated:0,Guarded:0}; incidents.forEach(item=>counts[item.riskBand]=(counts[item.riskBand]||0)+1); const total=Math.max(incidents.length,1); return <article className="panel risk-panel"><div className="panel-heading"><div><p className="eyebrow">Live distribution</p><h2>Risk posture</h2></div><span className="live-pill">Live</span></div><div className="risk-score"><div className="risk-ring"><strong>{Math.round(incidents.reduce((sum,item)=>sum+item.riskScore,0)/total)}</strong><small>Risk index</small></div></div><div className="risk-breakdown">{Object.entries(counts).map(([label,count])=><div><span><i className={`risk-dot ${label.toLowerCase()}`}></i>{label}</span><strong>{count}</strong><div className="mini-track"><i style={`width:${Math.round(count/total*100)}%`}></i></div></div>)}</div></article>; }
